import { StateCreator } from 'zustand';
import { db } from '../db';

export interface ExpenseSlice {
  expenses: Expense[];
  addExpense: (expense: Expense) => void;
  deleteExpense: (id: string) => void;
  hydrateExpenses: () => Promise<void>;
}

export const createExpenseSlice: StateCreator<ExpenseSlice> = (set) => ({
  expenses: [],
  addExpense: (expense) => {
    set((state) => ({ expenses: [expense, ...state.expenses] })); // optimistic
    db.expenses.add(expense); // persist
  },
  deleteExpense: (id) => {
    set((state) => ({ expenses: state.expenses.filter((e) => e.id !== id) }));
    db.expenses.delete(id);
  },
  hydrateExpenses: async () => {
    const expenses = await db.expenses.toArray();
    set({ expenses });
  },
});

