// computeMonthSummary.ts
export function computeMonthSummary(expenses: Expense[], budget: Budget): MonthSummary {
  const totalSpent = expenses.reduce((sum, e) => sum + e.amount, 0);
  const transactionCount = expenses.length;
  const daysInMonth = new Date(budget.month.slice(0,4), +budget.month.slice(5,7), 0).getDate();
  const dailyAverage = transactionCount > 0 ? totalSpent / daysInMonth : 0;
  const pct = totalSpent / budget.monthlyLimit;
  return {
    month: budget.month, totalSpent, transactionCount, dailyAverage,
    budgetLimit: budget.monthlyLimit,
    budgetStatus: pct > 1 ? 'Over Budget' : pct >= 0.8 ? 'Heads Up' : 'On Track',
    remainingAmount: budget.monthlyLimit - totalSpent,
  };
}

